import{_ as o,o as t,c as h,ai as l}from"./chunks/framework.CJDL-GS7.js";const p=JSON.parse('{"title":"Quản lý lớp học","description":"","frontmatter":{},"headers":[],"relativePath":"manage-classrooms.md","filePath":"manage-classrooms.md","lastUpdated":null}'),i={name:"manage-classrooms.md"};function a(s,n,r,c,g,e){return t(),h("div",null,[...n[0]||(n[0]=[l('<h1 id="quan-ly-lop-hoc" tabindex="-1">Quản lý lớp học <a class="header-anchor" href="#quan-ly-lop-hoc" aria-label="Permalink to &quot;Quản lý lớp học&quot;">​</a></h1><h2 id="tao-lop-hoc-moi" tabindex="-1">Tạo lớp học mới <a class="header-anchor" href="#tao-lop-hoc-moi" aria-label="Permalink to &quot;Tạo lớp học mới&quot;">​</a></h2><ol><li>Vào <strong>Lớp học</strong> → nhấn <strong>Tạo lớp học</strong></li><li>Điền thông tin: <ul><li><strong>Tên lớp</strong> — VD: &quot;10A1&quot;, &quot;Toán 11B&quot;</li><li><strong>Năm học</strong> — Chọn năm học hiện tại</li><li><strong>Môn học</strong> — Môn học tương ứng</li><li><strong>Giáo viên chủ nhiệm</strong> — Phân công giáo viên phụ trách</li></ul></li><li>Nhấn <strong>Tạo lớp</strong></li></ol><h2 id="them-hoc-sinh-vao-lop" tabindex="-1">Thêm học sinh vào lớp <a class="header-anchor" href="#them-hoc-sinh-vao-lop" aria-label="Permalink to &quot;Thêm học sinh vào lớp&quot;">​</a></h2><p><strong>Thêm từng học sinh:</strong></p><ol><li>Vào lớp học → tab <strong>Học sinh</strong> → nhấn <strong>Thêm học sinh</strong></li><li>Tìm kiếm theo tên hoặc email</li><li>Chọn học sinh → nhấn <strong>Thêm vào lớp</strong></li></ol><p><strong>Thêm hàng loạt:</strong></p><ol><li>Nhấn <strong>Nhập danh sách</strong></li><li>Tải file Excel mẫu, điền email học sinh</li><li>Tải lên → hệ thống tự động thêm vào lớp</li></ol><h2 id="phan-cong-giao-vien" tabindex="-1">Phân công giáo viên <a class="header-anchor" href="#phan-cong-giao-vien" aria-label="Permalink to &quot;Phân công giáo viên&quot;">​</a></h2><p>Một lớp học có thể có nhiều giáo viên dạy các môn khác nhau:</p><ol><li>Vào lớp học → tab <strong>Giáo viên</strong></li><li>Nhấn <strong>Thêm giáo viên</strong></li><li>Chọn giáo viên và môn phụ trách → nhấn <strong>Xác nhận</strong></li></ol><h2 id="quan-ly-nam-hoc" tabindex="-1">Quản lý năm học <a class="header-anchor" href="#quan-ly-nam-hoc" aria-label="Permalink to &quot;Quản lý năm học&quot;">​</a></h2><p>Vào <strong>Năm học</strong> trên sidebar:</p><ul><li><strong>Tạo năm học mới:</strong> Nhấn <strong>Thêm năm học</strong> → nhập tên (VD: &quot;2024-2025&quot;) và thời gian</li><li><strong>Năm học hiện tại:</strong> Đánh dấu một năm học là &quot;Đang hoạt động&quot; để làm mặc định</li><li><strong>Kết thúc năm học:</strong> Chuyển trạng thái sang &quot;Đã kết thúc&quot; khi năm học hoàn thành</li></ul><h2 id="quan-ly-mon-hoc" tabindex="-1">Quản lý môn học <a class="header-anchor" href="#quan-ly-mon-hoc" aria-label="Permalink to &quot;Quản lý môn học&quot;">​</a></h2><p>Vào <strong>Môn học</strong> trên sidebar:</p><ul><li><strong>Thêm môn học:</strong> Nhấn <strong>Thêm môn học</strong> → nhập tên môn</li><li><strong>Chỉnh sửa / Xoá:</strong> Nhấn biểu tượng tương ứng cạnh tên môn</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Tạo đầy đủ danh mục <strong>Năm học</strong> và <strong>Môn học</strong> trước khi tạo lớp học để việc phân loại được chính xác.</p></div>',18)])])}const u=o(i,[["render",a]]);export{p as __pageData,u as default};
